import type { Metadata } from "next";
import RegisterClose from "./RegisterClose";

export const metadata: Metadata = {
  title: "レジ締め / 日次精算 | ぐんじょうストア POS",
  description:
    "レジ締め（日次精算）の照合画面。店舗・レジ番号・担当者・営業日と締めステータス（営業中 / 締め処理中 / 締め完了）のヘッダ、総売上・取引件数・客単価・返品値引きと支払区分別内訳（現金 / クレジット / 電子マネー / QR / 商品券）の売上集計、金種ごとの枚数を入力して金額と実査現金合計を導く現金実査グリッド、開始釣銭＋現金売上±入出金＝理論現金残高に対する過不足（実査−理論、符号とアイコンと色で表示）の現金照合、釣銭追加・経費出金などの入出金ログ、翌日繰越釣銭と売上金回収、過不足が閾値超過時の理由必須化、締め確定 / 一時保存 / 印刷と精算レポートを備えたレジ締めツールです。",
};

export default function RegisterClosePage() {
  return <RegisterClose />;
}

/**
 * レジ締め / 日次精算 — domain data + pure cash-settlement math.
 * All money is whole JPY (no minor units). All math here is pure & deterministic
 * so the page never recomputes hydration-sensitive values.
 */

export type CloseStatus = "open" | "closing" | "closed"

/** 支払区分 (tender types). */
export type Tender = "cash" | "credit" | "emoney" | "qr" | "voucher"

export interface TenderLine {
  tender: Tender
  amount: number // ¥
  count: number // 取引件数
}

/** 入出金 (paid-in / paid-out) — affects drawer cash. */
export type CashMoveKind = "change_in" | "expense_out" | "deposit_out" | "other_in"

export interface CashMove {
  id: string
  kind: CashMoveKind
  label: string
  /** signed ¥: positive = cash into drawer, negative = cash out of drawer. */
  amount: number
  at: string // HH:mm
}

/** 金種 (denomination) — value in yen of one piece. */
export interface Denomination {
  yen: number
  /** "紙幣" | "硬貨" — bill vs coin, for grouping/labels. */
  kind: "bill" | "coin"
}

/** A counted denomination row (what the user edits). */
export interface DenomCount {
  yen: number
  kind: "bill" | "coin"
  count: number // 枚数
}

export const DENOMINATIONS: Denomination[] = [
  { yen: 10000, kind: "bill" },
  { yen: 5000, kind: "bill" },
  { yen: 1000, kind: "bill" },
  { yen: 500, kind: "coin" },
  { yen: 100, kind: "coin" },
  { yen: 50, kind: "coin" },
  { yen: 10, kind: "coin" },
  { yen: 5, kind: "coin" },
  { yen: 1, kind: "coin" },
]

export const TENDER_LABEL: Record<Tender, string> = {
  cash: "現金",
  credit: "クレジット",
  emoney: "電子マネー",
  qr: "QRコード",
  voucher: "商品券",
}

export const CASH_MOVE_LABEL: Record<CashMoveKind, string> = {
  change_in: "釣銭追加",
  other_in: "その他入金",
  expense_out: "経費出金",
  deposit_out: "売上金回収",
}

export const CLOSE_STATUS_META: Record<
  CloseStatus,
  { label: string; variant: "secondary" | "warning" | "success" }
> = {
  open: { label: "営業中", variant: "secondary" },
  closing: { label: "締め処理中", variant: "warning" },
  closed: { label: "締め完了", variant: "success" },
}

/** 過不足がこの額を超えると理由必須＋警告 (over/short threshold, abs ¥). */
export const VARIANCE_THRESHOLD = 1000

/** 過不足理由 (cash variance reason codes). */
export const VARIANCE_REASONS = [
  "釣銭間違い",
  "つり銭渡し過ぎ／不足",
  "入力ミス",
  "未記帳の入出金",
  "原因不明（要確認）",
] as const
export type VarianceReason = (typeof VARIANCE_REASONS)[number]

// ---- Seed data for the demo store ----

export const SALES_BY_TENDER: TenderLine[] = [
  { tender: "cash", amount: 142_350, count: 86 },
  { tender: "credit", amount: 318_900, count: 71 },
  { tender: "emoney", amount: 96_420, count: 58 },
  { tender: "qr", amount: 54_180, count: 33 },
  { tender: "voucher", amount: 12_000, count: 4 },
]

/** 返品・値引き合計 (already excluded from 総売上 below; shown for transparency). */
export const RETURNS_DISCOUNTS = 8_640

export const CASH_MOVES: CashMove[] = [
  { id: "m1", kind: "change_in", label: "開店時 釣銭補充", amount: 20_000, at: "09:55" },
  { id: "m2", kind: "expense_out", label: "備品購入（ゴミ袋）", amount: -1_280, at: "13:10" },
  { id: "m3", kind: "deposit_out", label: "中間回収（売上金）", amount: -100_000, at: "15:00" },
]

/** 開始釣銭準備金 (opening float). */
export const OPENING_FLOAT = 50_000

/** 翌日繰越 釣銭準備金 (target float to keep for tomorrow). */
export const CARRYOVER_FLOAT = 50_000

export const STORE_INFO = {
  store: "ぐんじょうストア 渋谷店",
  register: "レジ 2号機",
  operator: "田中 美咲",
  businessDate: "2026-06-23（月）",
  session: "遅番 15:00–22:00",
}

// ---- Pure math ----

export function denomAmount(yen: number, count: number): number {
  return yen * count
}

/** 実査現金合計 = Σ(金種 × 枚数). */
export function countedTotal(rows: DenomCount[]): number {
  return rows.reduce((sum, r) => sum + denomAmount(r.yen, r.count), 0)
}

export function tenderTotal(lines: TenderLine[]): number {
  return lines.reduce((sum, l) => sum + l.amount, 0)
}

export function tenderCount(lines: TenderLine[]): number {
  return lines.reduce((sum, l) => sum + l.count, 0)
}

export function cashSales(lines: TenderLine[]): number {
  return lines.find((l) => l.tender === "cash")?.amount ?? 0
}

/** Net of all 入出金 (signed). */
export function cashMovesNet(moves: CashMove[]): number {
  return moves.reduce((sum, m) => sum + m.amount, 0)
}

/** 理論現金残高 = 開始釣銭 + 現金売上 + Σ入出金(signed). */
export function theoreticalCash(
  openingFloat: number,
  cashSalesAmt: number,
  movesNet: number,
): number {
  return openingFloat + cashSalesAmt + movesNet
}

/** 過不足（差額）= 実査現金 − 理論現金. Negative = 不足(short), positive = 過剰(over). */
export function variance(counted: number, theoretical: number): number {
  return counted - theoretical
}

export type VarianceTone = "match" | "over" | "short"

export function varianceTone(v: number): VarianceTone {
  if (v === 0) return "match"
  return v > 0 ? "over" : "short"
}

/** 客単価 (average per transaction). */
export function averageTicket(total: number, count: number): number {
  return count > 0 ? Math.round(total / count) : 0
}

/** 売上金（回収）= 実査現金 − 翌日繰越釣銭準備金 (what goes to deposit). */
export function depositAmount(counted: number, carryover: number): number {
  return Math.max(0, counted - carryover)
}

export function makeInitialCounts(): DenomCount[] {
  return DENOMINATIONS.map((d) => ({ yen: d.yen, kind: d.kind, count: 0 }))
}
